/**
 * Clears the global CLI telemetry store.
 * @internal
 */
export declare function clearCliTelemetry(): void;

/**
 * @public
 * Symbol used to store CLI telemetry state on globalThis.
 * Use the accessor functions instead of accessing this directly.
 */
export declare const CLI_TELEMETRY_SYMBOL: unique symbol;

/**
 * @public
 */
declare type CLITelemetryStore = TelemetryLogger<TelemetryUserProperties>;

declare interface DeferredEvent<
  Data = unknown,
  Event extends DefinedTelemetryLog<Data> = DefinedTelemetryLog<Data>,
> {
  createdAt: string;
  event: Event;
  data: Data;
}

declare interface DefinedTelemetryLog<Schema> {
  type: "log";
  /** Unique name of the event */
  name: string;
  /** Event version. Increment this by 1 whenever the shape of the data changes in a non-backwards compatible way */
  version: number;
  /** Description of log event */
  description?: string;
  /**
   * Max sample rate of this event.
   * Calling telemetry.log(EventDefinition, data) repeatedly will submit at most one event every specified time interval (in milliseconds)
   * */
  maxSampleRate?: number;
  /** Data schema. Will not be accessible at runtime */
  schema: Schema;
}

declare interface DefinedTelemetryTrace<Data = void, Context = void> {
  type: "trace";
  /** Unique name of the trace */
  name: string;
  /** Trace version. Increment this by 1 whenever the shape of the data changes in a non-backwards compatible way */
  version: number;
  /** Description of trace */
  description?: string;
  /** Data schema. Will not be accessible at runtime */
  schema: Data;
  /** Contextual data schema. Will not be accessible at runtime */
  context: Context;
}

/**
 * @public
 */
export declare function getCliTelemetry(): CLITelemetryStore;

/**
 * Gets the base telemetry information needed for file operations.
 *
 * This shared utility extracts common logic used by:
 * - `generateTelemetryFilePath` - for generating session-specific file paths
 * - `findTelemetryFiles` - for discovering all telemetry files via glob patterns
 *
 * @returns Promise resolving to base telemetry information
 * @throws Error if no auth token is found
 * @internal
 */
export declare function getTelemetryBaseInfo(): Promise<TelemetryBaseInfo>;

/**
 * Fallback logger used when telemetry has not been initialized.
 * Exported for use in tests only — do not use in plugins or external code.
 * @internal
 */
export declare const noopLogger: CLITelemetryStore;

/**
 * Reports an error to the CLI command trace. Called from SanityCommand.catch()
 * for real command errors (not user aborts).
 * @internal
 */
export declare function reportCliTraceError(error: Error): void;

/**
 * Sets the global CLI telemetry state.
 * @internal
 */
export declare function setCliTelemetry(
  telemetry: CLITelemetryStore,
  options?: {
    reportTraceError?: TraceErrorReporter;
  },
): void;

/**
 * Base information needed for telemetry file operations.
 * Contains common data used by both file path generation and pattern matching.
 */
declare interface TelemetryBaseInfo {
  /** Base filename pattern without sessionId suffix */
  basePattern: string;
  /** Base directory where telemetry files are stored */
  directory: string;
  /** Environment: 'staging' or 'production' */
  environment: string;
  /** Hashed token (first 8 chars of SHA256) for privacy */
  hashedToken: string;
}

/**
 * Note that `sessionId` is removed from the signature of these functions
 */
declare interface TelemetryLogger<UserProperties> {
  updateUserProperties(properties: UserProperties): void;
  resume(events: DeferredEvent[]): void;
  log<Data>(event: DefinedTelemetryLog<Data>, data: Data): void;
  log<Data extends void>(event: DefinedTelemetryLog<Data>): void;
  trace<Data>(
    event: DefinedTelemetryTrace<Data>,
    context?: unknown,
  ): TelemetryTrace<UserProperties, Data>;
}

declare interface TelemetryTrace<UserProperties, Data> {
  start(): void;
  log(data: Data): void;
  error(error: Error): void;
  complete(): void;
  newContext(name: string): TelemetryLogger<UserProperties>;
  await<P extends Promise<Data>>(promise: P): P;
  await<P extends Promise<unknown>>(promise: P, finalData: Data): P;
}

/**
 * @public
 */
declare interface TelemetryUserProperties {
  cliVersion: string;
  cpuArchitecture: string;
  machinePlatform: string;
  runtime: string;
  runtimeVersion: string;
  dataset?: string;
  projectId?: string;
}

declare type TraceErrorReporter = (error: Error) => void;

export {};
